const s=new Date($checkIn);
const e=new Date($checkOut);
if(isNaN(s)||isNaN(e)||e<=s){return JSON.stringify({noches:0,minNoches:0,feriado:false});}
const noches=Math.max(1,Math.round((e-s)/(1000*60*60*24)));
const feriadoInicio=new Date('2024-08-09');
const feriadoFin=new Date('2024-08-12');
const feriado = s<=feriadoFin && e>=feriadoInicio;
const minNoches = feriado ? 3 : 1;
return JSON.stringify({noches,minNoches,feriado});

const hoy=new Date();
const ci=new Date($flow.state.checkIn||Date.now());
const dias=Math.ceil((ci-hoy)/(1000*60*60*24));
const tarifa=$flow.state.tarifaTipo||'refundable';
let penalidad=0;let tipo='porcentaje';
if(tarifa==='no_reembolsable'){penalidad=100;} else {penalidad = dias<=3 ? 50 : 0;}
return JSON.stringify({penalidad,penalidadTipo:tipo,dias});
